module RefModule(a, b, ci, out, co);parameter SIZE=8;
input [SIZE-1:0] a;
input [SIZE-1:0] b;
input ci;
output [SIZE-1:0] out;
output co;

wire [SIZE:0] obf_c;
assign obf_c[0] = ci;
assign co = obf_c[SIZE];

genvar i;
generate for(i=0; i<SIZE; i=i+1) begin:addbit
    assign out[i] = a[i] ^ b[i] ^ obf_c[i];
    assign obf_c[i+1] = (a[i] & b[i]) | (a[i] & obf_c[i]) | (b[i] & obf_c[i]);
end endgenerate

endmodule
